  input rw; 
  input [1:0] X;
  input [1:0] Y;
  input [1:0] Z;
  input [1:0] Pid;
  input Pz;
  input Pset;
  output Px;
  output Py;
  output Pval;

  reg obf_pregs [3:0];
  integer i;

  always @ (*) begin
